-- acryl-grid-fill-v2-dryrun.sql — 검증(ROLLBACK). 4격자 완전화 + 권위 verbatim 어서션.
BEGIN;
SELECT setval('public.t_prc_component_prices_comp_price_id_seq', (SELECT MAX(comp_price_id) FROM t_prc_component_prices));

\echo '===== AFTER: 격자 셀 수(기대 투명3T=196·투명1.5T=81·미러3T=81·코롯토=36) ====='
SELECT comp_cd, COALESCE(mat_cd,'(NULL)') mat, count(*) cells
FROM t_prc_component_prices WHERE comp_cd IN ('COMP_ACRYL_CLEAR3T','COMP_ACRYL_MIRROR3T','COMP_ACRYL_COROTTO')
GROUP BY comp_cd, mat_cd ORDER BY comp_cd, mat_cd;

DO $$ DECLARE c43 int; c42 int; cmir int; ccor int; BEGIN
  SELECT count(*) INTO c43 FROM t_prc_component_prices WHERE comp_cd='COMP_ACRYL_CLEAR3T' AND mat_cd='MAT_000043';
  SELECT count(*) INTO c42 FROM t_prc_component_prices WHERE comp_cd='COMP_ACRYL_CLEAR3T' AND mat_cd='MAT_000042';
  SELECT count(*) INTO cmir FROM t_prc_component_prices WHERE comp_cd='COMP_ACRYL_MIRROR3T';
  SELECT count(*) INTO ccor FROM t_prc_component_prices WHERE comp_cd='COMP_ACRYL_COROTTO';
  IF c43<>196 THEN RAISE EXCEPTION '투명3T %셀(기대 196)',c43; END IF;
  IF c42<>81  THEN RAISE EXCEPTION '투명1.5T %셀(기대 81)',c42; END IF;
  IF cmir<>81 THEN RAISE EXCEPTION '미러3T %셀(기대 81)',cmir; END IF;
  IF ccor<>36 THEN RAISE EXCEPTION '코롯토 %셀(기대 36)',ccor; END IF;
  RAISE NOTICE 'DRY-RUN OK: 4격자 권위 완전(196/81/81/36)·미적재 0·verbatim(대칭전개 0)';
END $$;
ROLLBACK;
\echo '===== ROLLBACK 완료 (라이브 미변경) ====='
